import React, { useState } from 'react';
import {
  Container,
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  IconButton,
  InputAdornment,
  Fade
} from '@mui/material';
import { Visibility, VisibilityOff, ArrowBack } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import bcrypt from 'bcryptjs';
import { supabase } from '../supabase';
import '../styles/styles.css';

const Register = ({ notificationsRef }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const errorMessages = {
    usernameRequired: 'Enter a username.',
    passwordRequired: 'Enter a password.',
    confirmPasswordRequired: 'Confirm your password.',
    passwordsMismatch: "Passwords don't match.",
    invalidUsername: 'Lowercase letters and numbers only.',
    usernameExists: 'Username already taken.',
    registrationSuccess: 'Done!',
    serverError: 'Something went wrong.',
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!username) {
      notificationsRef.current.showSnackbar(errorMessages.usernameRequired, 'error');
      return;
    }
    if (!password) {
      notificationsRef.current.showSnackbar(errorMessages.passwordRequired, 'error');
      return;
    }
    if (!confirmPassword) {
      notificationsRef.current.showSnackbar(errorMessages.confirmPasswordRequired, 'error');
      return;
    }
    if (password !== confirmPassword) {
      notificationsRef.current.showSnackbar(errorMessages.passwordsMismatch, 'error');
      return;
    }
    if (!/^[a-z0-9]+$/.test(username)) {
      notificationsRef.current.showSnackbar(errorMessages.invalidUsername, 'error');
      return;
    }

    setLoading(true);

    try {
      const { data: existing } = await supabase
        .from('users')
        .select('id')
        .eq('username', username)
        .single();

      if (existing) {
        notificationsRef.current.showSnackbar(errorMessages.usernameExists, 'error');
        setLoading(false);
        return;
      }

      const password_hash = await bcrypt.hash(password, 10);

      const { error } = await supabase
        .from('users')
        .insert([{ username, password_hash, avatar_url: '' }]);

      if (error) {
        notificationsRef.current.showSnackbar(errorMessages.serverError, 'error');
        setLoading(false);
        return;
      }

      notificationsRef.current.showSnackbar(errorMessages.registrationSuccess, 'success');
      setTimeout(() => navigate('/'), 2000);
    } catch (err) {
      notificationsRef.current.showSnackbar(errorMessages.serverError, 'error');
      setLoading(false);
    }
  };

  const handleClickShowPassword = () => setShowPassword((prev) => !prev);
  const handleMouseDownPassword = (event) => event.preventDefault();

  return (
    <Box className="registerContainer">
      <IconButton
        onClick={() => navigate(-1)}
        className="registerBackButton"
        color="primary"
      >
        <ArrowBack />
      </IconButton>

      <Container component="main" maxWidth="xs" className="registerMainContainer">
        <Fade in={true} timeout={1000}>
          <Paper elevation={3} className="registerPaper">
            <Box className="registerTitleBox">
              <Typography component="h1" variant="h5" className="registerTitle">
                Register
              </Typography>
            </Box>

            <form onSubmit={handleSubmit} noValidate>
              <TextField
                required
                fullWidth
                margin="normal"
                id="username"
                name="username"
                label="Username"
                autoComplete="username"
                autoFocus
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                InputProps={{ className: 'registerTextField' }}
              />

              <TextField
                required
                fullWidth
                margin="normal"
                id="password"
                name="password"
                label="Password"
                type={showPassword ? 'text' : 'password'}
                autoComplete="new-password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                InputProps={{
                  className: 'registerTextField',
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        aria-label="toggle password visibility"
                        onClick={handleClickShowPassword}
                        onMouseDown={handleMouseDownPassword}
                        edge="end"
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              <TextField
                required
                fullWidth
                margin="normal"
                id="confirmPassword"
                name="confirmPassword"
                label="Confirm Password"
                type={showPassword ? 'text' : 'password'}
                autoComplete="new-password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                InputProps={{
                  className: 'registerTextField',
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        aria-label="toggle password visibility"
                        onClick={handleClickShowPassword}
                        onMouseDown={handleMouseDownPassword}
                        edge="end"
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                className="registerSubmitButton"
                disabled={loading}
              >
                {loading ? 'Registering...' : 'Register'}
              </Button>
            </form>
          </Paper>
        </Fade>
      </Container>
    </Box>
  );
};

export default Register;