import React, { useState, useEffect } from 'react';
import { Typography, Paper, Box, TextField, Button, Avatar, Grid, IconButton } from '@mui/material';
import { PhotoCamera, Delete, ArrowBack } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import bcrypt from 'bcryptjs';
import { supabase } from '../supabase';
import '../styles/styles.css';

const Profile = ({ notificationsRef }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState({ username: '', avatarUrl: '' });
  const [formData, setFormData] = useState({ password: '', confirmPassword: '' });

  const messages = {
    passwordsMismatch: "Passwords don't match.",
    passwordUpdateSuccess: 'Password updated!',
    avatarUploadSuccess: 'Photo updated!',
    avatarRemoveSuccess: 'Photo removed.',
    serverError: 'Something went wrong.',
  };

  useEffect(() => {
    const userId = localStorage.getItem('user_id');
    const username = localStorage.getItem('username');

    if (!userId || !username) {
      navigate('/');
      return;
    }

    const fetchUser = async () => {
      const { data, error } = await supabase
        .from('users')
        .select('username, avatar_url')
        .eq('id', userId)
        .single();

      if (!error && data) {
        setUser({ username: data.username, avatarUrl: data.avatar_url || '' });
      }
    };

    fetchUser();
    setIsAuthenticated(true);
  }, [navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    if (formData.password !== formData.confirmPassword) {
      notificationsRef.current.showSnackbar(messages.passwordsMismatch, 'error');
      setLoading(false);
      return;
    }

    const userId = localStorage.getItem('user_id');
    const password_hash = await bcrypt.hash(formData.password, 10);

    const { error } = await supabase
      .from('users')
      .update({ password_hash })
      .eq('id', userId);

    if (error) {
      notificationsRef.current.showSnackbar(messages.serverError, 'error');
      setLoading(false);
      return;
    }

    notificationsRef.current.showSnackbar(messages.passwordUpdateSuccess, 'success');
    setFormData({ password: '', confirmPassword: '' });
    setLoading(false);
  };

  const handleUpload = (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async () => {
      const avatarUrl = reader.result;
      const userId = localStorage.getItem('user_id');

      const { error } = await supabase
        .from('users')
        .update({ avatar_url: avatarUrl })
        .eq('id', userId);

      if (error) {
        notificationsRef.current.showSnackbar(messages.serverError, 'error');
        return;
      }

      setUser((prev) => ({ ...prev, avatarUrl }));
      notificationsRef.current.showSnackbar(messages.avatarUploadSuccess, 'success');
    };
    reader.readAsDataURL(file);
  };

  const handleRemove = async () => {
    const userId = localStorage.getItem('user_id');

    const { error } = await supabase
      .from('users')
      .update({ avatar_url: '' })
      .eq('id', userId);

    if (error) {
      notificationsRef.current.showSnackbar(messages.serverError, 'error');
      return;
    }

    setUser((prev) => ({ ...prev, avatarUrl: '' }));
    notificationsRef.current.showSnackbar(messages.avatarRemoveSuccess, 'success');
  };

  if (!isAuthenticated) return null;

  return (
    <Box sx={{ minHeight: '100vh', width: '100vw', backgroundColor: '#f0f2f5', display: 'flex', justifyContent: 'center', alignItems: 'center', padding: '16px', boxSizing: 'border-box' }}>
      <Box sx={{ width: '100%', maxWidth: '600px' }}>
        <Paper elevation={2} className="paper">
          <IconButton
            onClick={() => navigate('/')}
            color="primary"
            className="backButton"
          >
            <ArrowBack />
          </IconButton>

          <Typography variant="h5" component="h1" mb={2}>
            Profile
          </Typography>

          <Box component="form" onSubmit={handleSubmit} className="form">
            <Grid container spacing={3}>
              <Grid item xs={12} display="flex" justifyContent="center" alignItems="center" flexDirection="column">
                <Avatar
                  sx={{ width: 100, height: 100 }}
                  src={user.avatarUrl}
                  alt={user.username}
                >
                  {user.username ? user.username[0].toUpperCase() : ''}
                </Avatar>
                <Box className="iconButton">
                  <IconButton color="primary" component="label">
                    <input hidden accept="image/*" type="file" onChange={handleUpload} />
                    <PhotoCamera />
                  </IconButton>
                  <IconButton color="secondary" onClick={handleRemove}>
                    <Delete />
                  </IconButton>
                </Box>
              </Grid>

              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="Username"
                  name="username"
                  value={user.username}
                  disabled
                  InputLabelProps={{ className: 'textFieldLabel' }}
                />
              </Grid>

              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="New Password"
                  name="password"
                  type="password"
                  value={formData.password}
                  onChange={handleChange}
                />
              </Grid>

              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="Confirm Password"
                  name="confirmPassword"
                  type="password"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                />
              </Grid>

              <Grid item xs={12}>
                <Button type="submit" variant="contained" fullWidth disabled={loading}>
                  {loading ? 'Updating...' : 'Save'}
                </Button>
              </Grid>
            </Grid>
          </Box>
        </Paper>
      </Box>
    </Box>
  );
};

export default Profile;